// Step 1: Create shader objects
vertexShader = glCreateShader(GL_VERTEX_SHADER)
fragmentShader = glCreateShader(GL_FRAGMENT_SHADER)

// Step 2: Load and compile shader source
glShaderSource(vertexShader, vertexShaderSource)
glCompileShader(vertexShader)
glShaderSource(fragmentShader, fragmentShaderSource)
glCompileShader(fragmentShader)

// Step 3: Check compilation errors
if glGetShaderiv(vertexShader, GL_COMPILE_STATUS) == GL_FALSE:
 logError(glGetShaderInfoLog(vertexShader))

// Step 4: Create and link program
program = glCreateProgram()
glAttachShader(program, vertexShader)
glAttachShader(program, fragmentShader)
glLinkProgram(program)

// Step 5: Use the program
glUseProgram(program)

// Step 6: Set uniforms
modelMatrix = createModelMatrix()
glUniformMatrix4fv(glGetUniformLocation(program, "uModel"), 1, modelMatrix)

// Step 7: Draw
glDrawElements(GL_TRIANGLES, 6, GL_UNSIGNED_INT, 0)

// Step 1: Generate and bind VAO
vao = glGenVertexArray()
glBindVertexArray(vao)

// Step 2: Generate and bind VBO for positions
vboPositions = glGenBuffer()
glBindBuffer(GL_ARRAY_BUFFER, vboPositions)
glBufferData(GL_ARRAY_BUFFER, positionData, GL_STATIC_DRAW)

// Step 3: Set up position attribute
glEnableVertexAttribArray(0) // attribute index 0
glVertexAttribPointer(0, 3, GL_FLOAT, GL_FALSE, 0, 0)

// Step 4: Generate and bind VBO for colors
vboColors = glGenBuffer()
glBindBuffer(GL_ARRAY_BUFFER, vboColors)
glBufferData(GL_ARRAY_BUFFER, colorData, GL_STATIC_DRAW)

// Step 5: Set up color attribute
glEnableVertexAttribArray(1) // attribute index 1
glVertexAttribPointer(1, 3, GL_FLOAT, GL_FALSE, 0, 0)

// Step 6: Generate and bind IBO
ibo = glGenBuffer()
glBindBuffer(GL_ELEMENT_ARRAY_BUFFER, ibo)
glBufferData(GL_ELEMENT_ARRAY_BUFFER, indexData, GL_STATIC_DRAW)

// Step 7: Unbind (optional)
glBindVertexArray(0)

// Later, to draw:
glBindVertexArray(vao)
glDrawElements(GL_TRIANGLES, 6, GL_UNSIGNED_INT, 0)

// Step 1: Create texture for color attachment
colorTexture = glGenTexture()
glBindTexture(GL_TEXTURE_2D, colorTexture)
glTexImage2D(GL_TEXTURE_2D, 0, GL_RGBA, width, height, 0, GL_RGBA, GL_UNSIGNED_BYTE, NULL)
glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_LINEAR)
glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_LINEAR)

// Step 2: Create depth renderbuffer
depthRB = glGenRenderbuffer()
glBindRenderbuffer(GL_RENDERBUFFER, depthRB)
glRenderbufferStorage(GL_RENDERBUFFER, GL_DEPTH_COMPONENT24, width, height)

// Step 3: Create and configure FBO
fbo = glGenFramebuffer()
glBindFramebuffer(GL_FRAMEBUFFER, fbo)

// Attach color texture
glFramebufferTexture2D(GL_FRAMEBUFFER, GL_COLOR_ATTACHMENT0, GL_TEXTURE_2D, colorTexture, 0)

// Attach depth renderbuffer
glFramebufferRenderbuffer(GL_FRAMEBUFFER, GL_DEPTH_ATTACHMENT, GL_RENDERBUFFER, depthRB)

// Step 4: Check FBO completeness
status = glCheckFramebufferStatus(GL_FRAMEBUFFER)
if status != GL_FRAMEBUFFER_COMPLETE:
 logError("FBO incomplete")

// Step 5: Unbind FBO (return to default framebuffer)
glBindFramebuffer(GL_FRAMEBUFFER, 0)

// To render to FBO:
glBindFramebuffer(GL_FRAMEBUFFER, fbo)
glViewport(0, 0, width, height)
// ... render scene ...

// To render to screen:
glBindFramebuffer(GL_FRAMEBUFFER, 0)
glViewport(0, 0, screenWidth, screenHeight)
